					// justifyContent: "center",
					width: isSm ? "100%" : "50%",
					// background: "blue",
					height: "100%"
				}}
			>
				<h1
					style={{
						fontWeight: "bold",
						fontSize: isSm ? "" : "3rem" || isMd ? "" : "3rem",
						paddingTop: "4rem",
						paddingBottom: "2rem"
					}}
				>
					Contact With Us
				</h1>
				<TextField
					required
					id="outlined-required"
					label="Name"
					name="name"
					size="normal"
					onChange={handleInputChange(setName)}
					style={{
						width: isSm ? "90%" : "75%",
						marginBottom: "1rem"
					}}
				/>
				<TextField
					required
					id="outlined-required"
					label="Email Address"
					name="email"
					onChange={handleInputChange(setEmail)}
					size="normal"
					style={{
						width: isSm ? "90%" : "75%",
						marginBottom: "1rem"
					}}
				/>
				<TextField
					required
					id="outlined-required"
					label="Phone Number"
					name="phone"
					onChange={handleInputChange(setPhone)}
					size="normal"
					style={{
						width: isSm ? "90%" : "75%",
						marginBottom: "1rem"
					}}
				/>

				<TextField
					required
					id="outlined-required"
					label="Your Message"
					name="message"
					onChange={handleInputChange(setMessage)}
					size="normal"
					multiline={true}
					// maxRows={6}
					rows={6}
					style={{
						width: isSm ? "90%" : "75%",
						marginBottom: "1rem"
					}}
