	  );

	const HandleClick = async (id) => {
		try {
			const res = await axios.patch(
				`https://kodo-backend.kodoscholarship.com/api/v1/user/notifications/${id}`,
				config
			);
			
			setClickedIds([...clickedIds, id]);

