      );
      // console.log(res?.data, "==");
      setData(res?.data?.data);
      setSubscription(res.data.subscription);

    } catch (error) {
      console.log(error);
    }
  };

  const handleClick = async (fav) => {
    try {
      const res = await axios.post(
        `${BASE_URL}/user/favourites`,
        {
          id: fav,
        },
        config
      );

      displaySuccessNotification(`${res.data.message}`);
