          <h4 style={{ textAlign: "center", padding: "1rem" }}>
            {data.length < 1 ? " " : "Loading..."}
          </h4>
        }
        endMessage={
          <h4 style={{ textAlign: "center", padding: "1rem" }}>
            <b>Thats all we have for you</b>
          </h4>
        }
      >
        {subscription
          ? data.map((dta) => (
              <LargeCard
                key={dta._id}
                title={dta.title}
