                    type="primary"
                    onClick={closeModal}
                    style={{
                        background: "none",
                        border: `2px solid #EB1E5E`,
                        color: "#EB1E5E",
                        padding: 2,
                        width: "5rem",
                        marginLeft: "1rem",
                    }}
                >
                    Close
                </Button>
            </div>

            {open && (
                <div
                    style={{
                        borderRadius: "50%",
                        background: "white",
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "space-evenly",
                        padding: "10px 0px 10px 0px",
                    }}
                >
                    {items.map((item) => (
                        <button
                            onClick={() => closeModal()}
                            style={{ height: "40px", width: "40px" }}
                            key={item.key}
                        >
                            {item.children}
                        </button>
                    ))}
                </div>
            )}
        </Modal>
    );
};

