							</div>
				  <form className="auth-form" onSubmit={register}
					style={{
					  marginTop: 30
					}}
				  >
					<div className="form-group">
					  <input 
						type="text" 
						placeholder="Email" 
						required 
						onChange={handleEmailChange}
