import {
	configureStore,
	combineReducers,
	getDefaultMiddleware
} from "@reduxjs/toolkit";

import {
	persistStore,
	persistReducer,
	FLUSH,
	REHYDRATE,
	PURGE,
	REGISTER,
	PAUSE,
	PERSIST
} from "redux-persist";
import storage from "redux-persist/lib/storage"; // Defaults to localStorage for web
import userReducer from "./toolkit/userReducer";
import formReducer from "./toolkit/formReducer";
import sportsReducer from "./toolkit/sportsReducer";
import jobReducer from "./toolkit/jobReducer";
import scholarshipReducer from "./toolkit/scholarshipReducer";

// Combine reducers
const rootReducer = combineReducers({
	user: userReducer,
	formData: formReducer,
	sportsData: sportsReducer,
	jobData: jobReducer,
	scholarship: scholarshipReducer
});

// Configure persistence options
const persistConfig = {
	key: "root",
	storage
	// Add any additional configuration options here
};

// Create persisted reducer
const persistedReducer = persistReducer(persistConfig, rootReducer);

// Create the Redux store
const store = configureStore({
	reducer: persistedReducer,
	devTools: process.env.NODE_ENV !== "production",
	middleware: (getDefaultMiddleware) =>
		getDefaultMiddleware({
			serializableCheck: {
				ignoredActions: [FLUSH, REGISTER, PAUSE, PURGE, REHYDRATE, PERSIST]
			}
		})
});

// Create persistor
const persistor = persistStore(store);

export { store, persistor };

import { useState, useMemo } from "react";
import axios from "axios";

const useCurrencyConverter = (fee) => {
  const dataUser = JSON.parse(localStorage.getItem("userData"));

  const countries = [
    {
      id: 1,
      country: "uganda",
      curr: "UGX",
    },
    {
      id: 2,
      country: "rwanda",
      curr: "RWF",
    },
    {
      id: 3,
      country: "kenya",
      curr: "KES",
    },
    {
      id: 4,
      country: "nigeria",
      curr: "NGN",
    },
    {
      id: 5,
      country: "ghana",
      curr: "GHS",
    },
    {
      id: 6,
      country: "tanzania",
      curr: "TZS",
    },
    {
      id: 7,
      country: "zambia",
      curr: "ZMW",
    },
    {
      id: 8,
      country: "Sierra Leone",
      curr: "SLL",
    },
    {
      id: 9,
      country: "cameroon",
      curr: "XOF",
    },

    {
      id: 10,
      country: "zimbabwe",
      curr: "XOF",
    },
  ];

  const filteredCountries = countries.filter(
    (countryObj) =>
      countryObj.country.toLowerCase() === dataUser?.user.country.toLowerCase()
  );

  const [baseState, setBaseState] = useState({
    currencies: [
      "USD",
      "UGX",
      "KES",
      "NGN",
      "RWF",
      "TZS",
      "SLL",
      "GHS",
      "ZMW",
      "XOF",
    ],
    base: "USD",
    amount: fee?.toString(),
    convertTo:
      filteredCountries[0]?.curr === null || undefined
        ? "USD"
        : filteredCountries[0]?.curr,
    result: "",
  });

  const { currencies, base, amount, convertTo } = baseState;

  useMemo(() => {
    if (amount === isNaN) {
      return;
    } else {
      const getCurrencyConverter = async () => {
        try {
          const response = await axios.get(
            `https://openexchangerates.org/api/latest.json?app_id=9109134d78fa4fa6a12f3f7bfa0b1934&base=${base}`
          );
          const result = (response?.data?.rates[convertTo] * amount).toFixed(3);
          setBaseState((prevBaseState) => ({
            ...prevBaseState,
            result,
          }));
        } catch (error) {
          console.error("Error fetching data: ", error);
        }
      };

      getCurrencyConverter();
    }
  }, [amount, base, convertTo]);

  return baseState;
};

export default useCurrencyConverter;
